class Solution {
    public int[] maximumCount(int[] nums, int[][] queries) {
        int n = nums.length;
        boolean[] isPrime = new boolean[10001];
        Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= 10000; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= 10000; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        int[] primes = new int[n];
        int count = 0;
        for (int num : nums) {
            if (isPrime[num]) {
                primes[count++] = num;
            }
        }
        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int idx = queries[i][0];
            int val = queries[i][1];
            nums[idx] = val;
            int[] leftPrimes = Arrays.copyOfRange(primes, 0, count);
            int[] rightPrimes = new int[count];
            int rightCount = 0;
            for (int j = idx + 1; j < n; j++) {
                if (isPrime[nums[j]]) {
                    rightPrimes[rightCount++] = nums[j];
                }
            }
            int left = 0, right = 0;
            for (int j = 0; j < count; j++) {
                if (Arrays.binarySearch(leftPrimes, primes[j]) >= 0) {
                    left++;
                }
                if (Arrays.binarySearch(rightPrimes, primes[j]) >= 0) {
                    right++;
                }
            }
            result[i] = Math.max(left, right);
        }
        return result;
    }
}
